-- Addon namespace
local _, Private = ...
local L = Private.Libs.ACL

-- Global environment
local _G = _G

local function elvCastbarCheck()
	if not Private.ElvUI then return end
	ElvUI[1].db.unitframe.units.player.castbar.enable = false
end

